"""
ppt_generator.py — INTERLOG KPI Dashboard
Genera el PowerPoint mensual con branding INTERLOG.

Uso:
    from ppt_generator import generar_ppt
    buf = generar_ppt(lib_items, ofi_items, cm_pre_items, cm_apr_items, mes)
"""

import io
import base64
import tempfile
import os
from pptx import Presentation
from pptx.util import Inches, Pt, Emu
from pptx.dml.color import RGBColor
from pptx.enum.text import PP_ALIGN
from pptx.util import Inches, Pt

# ── Colores INTERLOG ──────────────────────────────────────────────────────────
TEAL      = RGBColor(0x3F, 0xA8, 0x9C)
NARANJA   = RGBColor(0xD4, 0x69, 0x0A)
ROJO      = RGBColor(0xC0, 0x39, 0x2B)
VERDE     = RGBColor(0x27, 0xAE, 0x60)
GRIS_OSC  = RGBColor(0x1E, 0x2D, 0x35)
GRIS_CARD = RGBColor(0xF0, 0xF4, 0xF6)
BLANCO    = RGBColor(0xFF, 0xFF, 0xFF)
GRIS_MED  = RGBColor(0xCC, 0xCC, 0xCC)
GRIS_BORDE= RGBColor(0xDD, 0xDD, 0xDD)

# ── Dimensiones slide ─────────────────────────────────────────────────────────
W = Inches(13.33)
H = Inches(7.5)

# ── Imágenes de fondo en base64 ───────────────────────────────────────────────
_BG_PORTADA_B64 = """"""

_BG_CONTENIDO_B64 = """"""


# ── Helpers ───────────────────────────────────────────────────────────────────

def _rgb_hex(color: RGBColor) -> str:
    return f"{color[0]:02X}{color[1]:02X}{color[2]:02X}"


def _kpi_color(pct: float) -> RGBColor:
    if pct >= 95:
        return TEAL
    elif pct >= 80:
        return NARANJA
    return ROJO


def _add_bg(slide, b64_str: str):
    """Inserta imagen de fondo a tamaño completo."""
    data = base64.b64decode(b64_str)
    with tempfile.NamedTemporaryFile(suffix=".jpg", delete=False) as tf:
        tf.write(data)
        tf.flush()
        pic = slide.shapes.add_picture(tf.name, 0, 0, W, H)
    os.unlink(tf.name)
    # Mover al fondo
    slide.shapes._spTree.remove(pic._element)
    slide.shapes._spTree.insert(2, pic._element)


def _rect(slide, x, y, w, h, fill=None, line_color=None, line_w=Pt(0.5)):
    """Agrega un rectángulo."""
    shape = slide.shapes.add_shape(1, x, y, w, h)  # MSO_SHAPE_TYPE.RECTANGLE
    shape.line.fill.background()
    if fill:
        shape.fill.solid()
        shape.fill.fore_color.rgb = fill
    else:
        shape.fill.background()
    if line_color:
        shape.line.color.rgb = line_color
        shape.line.width = line_w
    else:
        shape.line.fill.background()
    return shape


def _text(slide, text, x, y, w, h, size=12, bold=False, color=GRIS_OSC,
          align=PP_ALIGN.LEFT, v_anchor="top", italic=False, font="Calibri"):
    """Agrega un cuadro de texto."""
    from pptx.enum.text import MSO_ANCHOR
    tf = slide.shapes.add_textbox(x, y, w, h)
    tf.text_frame.word_wrap = True
    if v_anchor == "middle":
        tf.text_frame.vertical_anchor = MSO_ANCHOR.MIDDLE
    elif v_anchor == "bottom":
        tf.text_frame.vertical_anchor = MSO_ANCHOR.BOTTOM
    p = tf.text_frame.paragraphs[0]
    p.alignment = align
    run = p.add_run()
    run.text = text
    run.font.size = Pt(size)
    run.font.bold = bold
    run.font.italic = italic
    run.font.color.rgb = color
    run.font.name = font
    return tf


def _slide_header(slide, title: str):
    """Header estándar: título + línea teal."""
    _text(slide, title, Inches(0.45), Inches(0.3), Inches(12), Inches(0.55),
          size=22, bold=True, color=GRIS_OSC, font="Calibri")
    _rect(slide, Inches(0.45), Inches(0.88), Inches(3.0), Inches(0.045), fill=TEAL)


def _footer(slide):
    """Footer estándar con logo y URL."""
    # Línea divisoria
    _rect(slide, 0, Inches(7.08), W, Inches(0.01), fill=GRIS_MED)
    # URL texto
    _text(slide, "interlog.com.ar", Inches(10.0), Inches(7.12), Inches(3.0), Inches(0.35),
          size=9, color=RGBColor(0x88, 0x88, 0x88), align=PP_ALIGN.RIGHT)
    # Target note (a veces en algunas slides)


def _metric_card(slide, x, y, w, h, value: str, label: str, 
                 val_color=GRIS_OSC, border_color=None):
    """Card de métrica: valor grande + label."""
    # Fondo
    _rect(slide, x, y, w, h, fill=BLANCO, 
          line_color=GRIS_BORDE if not border_color else border_color,
          line_w=Pt(0.75))
    # Acento izquierdo
    if border_color:
        _rect(slide, x, y, Inches(0.05), h, fill=border_color)
    # Valor
    _text(slide, value, x + Inches(0.15), y + Inches(0.25), w - Inches(0.2), Inches(0.55),
          size=28, bold=True, color=val_color, align=PP_ALIGN.CENTER, font="Calibri")
    # Label
    _text(slide, label, x + Inches(0.1), y + h - Inches(0.45), w - Inches(0.2), Inches(0.4),
          size=9, bold=True, color=GRIS_OSC, align=PP_ALIGN.CENTER, font="Calibri")


def _kpi_main_card(slide, x, y, w, h, pct: float, title1: str, title2: str,
                   n_total: int, unit="operaciones"):
    """Card grande de KPI para resumen ejecutivo."""
    kpi_col = _kpi_color(pct)
    _rect(slide, x, y, w, h, fill=BLANCO, line_color=GRIS_BORDE, line_w=Pt(0.75))
    # Acento izquierdo color
    _rect(slide, x, y, Inches(0.055), h, fill=kpi_col)
    # Porcentaje
    _text(slide, f"{pct:.0f}%", x + Inches(0.12), y + Inches(0.55), w - Inches(0.15), Inches(0.65),
          size=32, bold=True, color=kpi_col, align=PP_ALIGN.CENTER, font="Calibri")
    # Título línea 1
    _text(slide, title1, x + Inches(0.1), y + Inches(1.22), w - Inches(0.15), Inches(0.25),
          size=8, bold=True, color=GRIS_OSC, align=PP_ALIGN.CENTER, font="Calibri")
    # Título línea 2
    _text(slide, title2, x + Inches(0.1), y + Inches(1.44), w - Inches(0.15), Inches(0.25),
          size=8, bold=True, color=GRIS_OSC, align=PP_ALIGN.CENTER, font="Calibri")
    # N operaciones
    _text(slide, f"{n_total} {unit}", x + Inches(0.1), y + Inches(1.68), w - Inches(0.15), Inches(0.25),
          size=8, color=RGBColor(0x88, 0x88, 0x88), align=PP_ALIGN.CENTER, font="Calibri")


def _hbar_canal(slide, x, y, bar_w, bar_h, label: str, n_in: int, n_total: int,
                bar_color: RGBColor):
    """Barra horizontal de canal (verde/naranja/rojo) con etiqueta y ratio."""
    # Label (VERDE / NARANJA / ROJO)
    _text(slide, label, x, y, Inches(0.65), bar_h,
          size=7, bold=False, color=RGBColor(0x66, 0x66, 0x66), font="Calibri")
    bx = x + Inches(0.67)
    # Fondo gris
    _rect(slide, bx, y + bar_h * 0.15, bar_w, bar_h * 0.7, fill=GRIS_CARD, line_color=None)
    # Barra rellena
    if n_total > 0:
        ratio = n_in / n_total
        fill_w = int(bar_w * ratio)
        if fill_w > 0:
            _rect(slide, bx, y + bar_h * 0.15, fill_w, bar_h * 0.7, fill=bar_color, line_color=None)
    # Texto ratio y %
    if n_total > 0:
        pct = n_in / n_total * 100
        ratio_text = f"{n_in}/{n_total}"
        pct_text = f"{pct:.0f}%"
    else:
        ratio_text = "—"
        pct_text = "—"
    _text(slide, ratio_text, bx, y + bar_h * 0.85, Inches(0.5), bar_h * 0.5,
          size=7, color=GRIS_OSC, font="Calibri")
    _text(slide, pct_text, bx + bar_w - Inches(0.5), y + bar_h * 0.85, Inches(0.5), bar_h * 0.5,
          size=7, bold=True,
          color=bar_color if n_total > 0 else GRIS_MED,
          align=PP_ALIGN.RIGHT, font="Calibri")


def _via_row(slide, x, y, row_w, via_name: str, n_ops: int, n_in: int, n_out: int,
             verde_in: int, verde_tot: int,
             naranja_in: int, naranja_tot: int,
             rojo_in: int, rojo_tot: int):
    """Fila completa de vía en slides de liberación."""
    kpi_pct = (n_in / n_ops * 100) if n_ops > 0 else 0
    kpi_col = _kpi_color(kpi_pct)
    row_h = Inches(1.0)

    # Panel izquierdo gris
    panel_w = Inches(2.6)
    _rect(slide, x, y, panel_w, row_h, fill=GRIS_CARD, line_color=GRIS_BORDE, line_w=Pt(0.5))
    # Acento color izq
    _rect(slide, x, y, Inches(0.05), row_h, fill=kpi_col)
    # Nombre vía
    _text(slide, via_name, x + Inches(0.15), y + Inches(0.08), panel_w - Inches(0.2), Inches(0.3),
          size=11, bold=True, color=GRIS_OSC, font="Calibri")
    # Subtítulo ops
    _text(slide, f"{n_ops} ops · {n_in} IN · {n_out} OUT",
          x + Inches(0.15), y + Inches(0.42), panel_w - Inches(0.2), Inches(0.25),
          size=8, color=RGBColor(0x77, 0x77, 0x77), font="Calibri")
    # KPI %
    _text(slide, f"{kpi_pct:.0f}%",
          x + Inches(0.15), y + Inches(0.6), panel_w - Inches(0.2), Inches(0.38),
          size=20, bold=True, color=kpi_col, font="Calibri")

    # 3 barras horizontales
    bars_x = x + panel_w + Inches(0.15)
    bars_w = (row_w - panel_w - Inches(0.2)) / 3
    bar_h = Inches(0.6)
    bar_y = y + Inches(0.2)

    _hbar_canal(slide, bars_x, bar_y, bars_w - Inches(0.1), bar_h,
                "VERDE", verde_in, verde_tot, VERDE)
    _hbar_canal(slide, bars_x + bars_w, bar_y, bars_w - Inches(0.1), bar_h,
                "NARANJA", naranja_in, naranja_tot, NARANJA)
    _hbar_canal(slide, bars_x + bars_w * 2, bar_y, bars_w - Inches(0.1), bar_h,
                "ROJO", rojo_in, rojo_tot, ROJO)


def _two_panel_kpi(slide, label_left: str, subtitle_left: str, limite_str: str,
                   n_total: int, n_in: int, n_out: int,
                   pct: float,
                   panel_x: float, panel_w_total: float):
    """Panel de 2 columnas para oficialización y canal verde."""
    left_w = Inches(2.8)
    right_w = panel_w_total - left_w - Inches(0.15)
    y = Inches(1.05)
    h = Inches(5.7)
    kpi_col = _kpi_color(pct)

    # Panel izquierdo (info contextual)
    _rect(slide, panel_x, y, left_w, h, fill=GRIS_CARD,
          line_color=TEAL, line_w=Pt(1.5))
    _rect(slide, panel_x, y, Inches(0.06), h, fill=TEAL)

    tx = panel_x + Inches(0.2)
    _text(slide, label_left, tx, y + Inches(0.18), left_w - Inches(0.25), Inches(0.4),
          size=14, bold=True, color=GRIS_OSC, font="Calibri")
    _text(slide, subtitle_left, tx, y + Inches(0.6), left_w - Inches(0.25), Inches(0.25),
          size=8, bold=True, color=RGBColor(0x88, 0x88, 0x88), font="Calibri")
    # Línea divisora
    _rect(slide, tx, y + Inches(0.9), left_w - Inches(0.4), Inches(0.02), fill=GRIS_MED)

    _text(slide, "TARGET", tx, y + Inches(1.05), left_w - Inches(0.25), Inches(0.25),
          size=8, bold=True, color=RGBColor(0x88, 0x88, 0x88), font="Calibri")
    _text(slide, "95%", tx, y + Inches(1.3), left_w - Inches(0.25), Inches(0.35),
          size=14, bold=True, color=GRIS_OSC, font="Calibri")
    _text(slide, "LÍMITE", tx, y + Inches(1.75), left_w - Inches(0.25), Inches(0.25),
          size=8, bold=True, color=RGBColor(0x88, 0x88, 0x88), font="Calibri")
    _text(slide, limite_str, tx, y + Inches(2.0), left_w - Inches(0.25), Inches(0.4),
          size=14, bold=True, color=GRIS_OSC, font="Calibri")
    # Línea divisora
    _rect(slide, tx, y + Inches(2.55), left_w - Inches(0.4), Inches(0.02), fill=GRIS_MED)

    _text(slide, str(n_total), tx, y + Inches(2.7), Inches(0.7), Inches(0.4),
          size=20, bold=True, color=GRIS_OSC, font="Calibri")
    _text(slide, "TOTAL", tx + Inches(0.75), y + Inches(2.8), Inches(1.5), Inches(0.3),
          size=9, color=RGBColor(0x88, 0x88, 0x88), font="Calibri")
    _text(slide, str(n_in), tx, y + Inches(3.2), Inches(0.7), Inches(0.4),
          size=20, bold=True, color=TEAL, font="Calibri")
    _text(slide, "IN", tx + Inches(0.75), y + Inches(3.3), Inches(1.5), Inches(0.3),
          size=9, color=RGBColor(0x88, 0x88, 0x88), font="Calibri")
    _text(slide, str(n_out), tx, y + Inches(3.7), Inches(0.7), Inches(0.4),
          size=20, bold=True, color=kpi_col if n_out > 0 else GRIS_OSC, font="Calibri")
    _text(slide, "OUT", tx + Inches(0.75), y + Inches(3.8), Inches(1.5), Inches(0.3),
          size=9, color=RGBColor(0x88, 0x88, 0x88), font="Calibri")

    # Panel derecho (KPI grande + barra)
    rx = panel_x + left_w + Inches(0.15)
    _text(slide, f"{pct:.0f}%", rx, y + Inches(1.3), right_w, Inches(1.2),
          size=52, bold=True, color=kpi_col, align=PP_ALIGN.CENTER, font="Calibri")

    # Barra KPI
    bar_y = y + Inches(3.0)
    bar_h = Inches(0.28)
    bar_full_w = right_w - Inches(0.3)
    bx = rx + Inches(0.15)
    _rect(slide, bx, bar_y, bar_full_w, bar_h, fill=GRIS_CARD, line_color=None)
    if pct > 0:
        _rect(slide, bx, bar_y, int(bar_full_w * pct / 100), bar_h, fill=kpi_col, line_color=None)

    _text(slide, "KPI IN", rx, bar_y - Inches(0.3), right_w, Inches(0.28),
          size=8, bold=True, color=RGBColor(0x88, 0x88, 0x88), align=PP_ALIGN.CENTER, font="Calibri")
    _text(slide, "TARGET 95%", rx, bar_y + bar_h + Inches(0.05), right_w, Inches(0.25),
          size=8, color=RGBColor(0x88, 0x88, 0x88), align=PP_ALIGN.CENTER, font="Calibri")


# ── Funciones por slide ───────────────────────────────────────────────────────

def _slide_portada(prs, mes: str):
    slide = prs.slides.add_slide(prs.slide_layouts[6])
    _add_bg(slide, _BG_PORTADA_B64)
    # Textos sobre el overlay teal derecho
    _text(slide, "KPI FASA / FSM", Inches(7.5), Inches(2.3), Inches(5.5), Inches(0.75),
          size=26, bold=True, color=GRIS_OSC, align=PP_ALIGN.CENTER, font="Calibri")
    _text(slide, mes.upper(), Inches(7.5), Inches(3.1), Inches(5.5), Inches(0.6),
          size=22, bold=True, color=GRIS_OSC, align=PP_ALIGN.CENTER, font="Calibri")
    _text(slide, "Reporte de Indicadores de Desempeño",
          Inches(7.5), Inches(3.75), Inches(5.5), Inches(0.4),
          size=11, color=GRIS_OSC, align=PP_ALIGN.CENTER, italic=True, font="Calibri")
    _text(slide, "interlog.com.ar", Inches(0.25), Inches(6.8), Inches(3.0), Inches(0.35),
          size=10, color=BLANCO, font="Calibri")


def _slide_resumen(prs, lib_items, ofi_items, cm_pre_items):
    from collections import defaultdict

    def kpi(items):
        if not items:
            return 0.0, 0, 0, 0
        total = len(items)
        n_in = sum(1 for x in items if x.get("estado") == "IN")
        n_out = total - n_in
        pct = n_in / total * 100 if total > 0 else 0
        return pct, n_in, n_out, total

    fasa_lib = [x for x in lib_items if "FINNING ARGENTINA" in x.get("razon_social","").upper()]
    fsm_lib  = [x for x in lib_items if "FINNING SOLUCIONES" in x.get("razon_social","").upper()]
    fasa_ofi = [x for x in ofi_items if "FINNING ARGENTINA" in x.get("razon_social","").upper()]
    fsm_ofi  = [x for x in ofi_items if "FINNING SOLUCIONES" in x.get("razon_social","").upper()]

    kpi_fasa_lib   = kpi(fasa_lib)
    kpi_fsm_lib    = kpi(fsm_lib)
    kpi_fasa_ofi   = kpi(fasa_ofi)
    kpi_fsm_ofi    = kpi(fsm_ofi)
    kpi_cm_pre     = kpi(cm_pre_items)

    slide = prs.slides.add_slide(prs.slide_layouts[6])
    _add_bg(slide, _BG_CONTENIDO_B64)
    _slide_header(slide, "RESUMEN EJECUTIVO")

    # 5 tarjetas KPI
    cards = [
        (kpi_fasa_lib[0], "LIBERACIÓN", "FASA", kpi_fasa_lib[3], "operaciones"),
        (kpi_fsm_lib[0],  "LIBERACIÓN", "FSM",  kpi_fsm_lib[3],  "operaciones"),
        (kpi_fasa_ofi[0], "OFICIALIZACIÓN", "FASA", kpi_fasa_ofi[3], "operaciones"),
        (kpi_fsm_ofi[0],  "OFICIALIZACIÓN", "FSM",  kpi_fsm_ofi[3],  "operaciones"),
        (kpi_cm_pre[0],   "CM", "PRESENTADOS", kpi_cm_pre[3], "expedientes"),
    ]
    card_w = Inches(2.45)
    card_h = Inches(2.2)
    gap = Inches(0.22)
    start_x = Inches(0.45)
    card_y = Inches(1.05)

    for i, (pct, t1, t2, ntotal, unit) in enumerate(cards):
        cx = start_x + i * (card_w + gap)
        _kpi_main_card(slide, cx, card_y, card_w, card_h, pct, t1, t2, ntotal, unit)

    # Target note
    _text(slide, "Target: 95%  ·  Parámetro ≠ INTERLOG → operación IN",
          Inches(0.45), Inches(3.4), Inches(12), Inches(0.3),
          size=9, color=RGBColor(0x88, 0x88, 0x88), align=PP_ALIGN.CENTER, font="Calibri")

    # Sección Desvíos Imputables
    _text(slide, "DESVÍOS IMPUTABLES A INTERLOG",
          Inches(0.45), Inches(3.85), Inches(6), Inches(0.35),
          size=11, bold=True, color=TEAL, font="Calibri")

    # Calcular OUT imputables (estado OUT y parámetro INTERLOG o sin especificar)
    def out_interlog(items):
        return sum(1 for x in items 
                   if x.get("estado") == "OUT" and 
                   (not x.get("parametro") or "INTERLOG" in str(x.get("parametro","")).upper()))

    dev_cards = [
        (f"FASA · Liberación", out_interlog(fasa_lib), kpi_fasa_lib[3]),
        (f"FSM · Liberación",  out_interlog(fsm_lib),  kpi_fsm_lib[3]),
        (f"FASA · Oficialización", out_interlog(fasa_ofi), kpi_fasa_ofi[3]),
        (f"FSM · Oficialización",  out_interlog(fsm_ofi),  kpi_fsm_ofi[3]),
    ]
    dev_card_w = Inches(2.95)
    dev_card_h = Inches(0.75)
    dev_gap = Inches(0.2)
    dev_y = Inches(4.27)

    for i, (titulo, n_out, n_total) in enumerate(dev_cards):
        dx = Inches(0.45) + i * (dev_card_w + dev_gap)
        _rect(slide, dx, dev_y, dev_card_w, dev_card_h, fill=BLANCO,
              line_color=GRIS_BORDE, line_w=Pt(0.75))
        _text(slide, titulo, dx + Inches(0.15), dev_y + Inches(0.06),
              dev_card_w - Inches(0.2), Inches(0.25),
              size=8, color=GRIS_OSC, font="Calibri")
        col = ROJO if n_out > 0 else TEAL
        _text(slide, f"{n_out} OUT", dx + Inches(0.15), dev_y + Inches(0.3),
              Inches(1.2), Inches(0.35), size=13, bold=True, color=col, font="Calibri")
        _text(slide, f"de {n_total} ops",
              dx + Inches(1.5), dev_y + Inches(0.35), Inches(1.2), Inches(0.28),
              size=9, color=RGBColor(0x88, 0x88, 0x88), font="Calibri")



def _slide_liberacion(prs, empresa: str, lib_items):
    """Slide de liberación para FASA o FSM."""
    items_emp = [x for x in lib_items if empresa.upper() in x.get("razon_social","").upper()]

    total = len(items_emp)
    n_in  = sum(1 for x in items_emp if x.get("estado") == "IN")
    n_out = total - n_in
    kpi_pct = n_in / total * 100 if total > 0 else 0
    kpi_col = _kpi_color(kpi_pct)

    slide = prs.slides.add_slide(prs.slide_layouts[6])
    _add_bg(slide, _BG_CONTENIDO_B64)
    label = "FASA" if "ARGENTINA" in empresa.upper() else "FSM"
    _slide_header(slide, f"{label} · LIBERACIÓN")

    # Sección RESUMEN
    _text(slide, "RESUMEN", Inches(0.45), Inches(1.05), Inches(3), Inches(0.3),
          size=10, bold=True, color=TEAL, font="Calibri")

    metric_cards = [
        (str(total), "TOTAL OPS", GRIS_OSC),
        (str(n_in), "IN", TEAL),
        (str(n_out), "OUT", ROJO if n_out > 0 else GRIS_OSC),
        (f"{kpi_pct:.0f}%", "KPI", kpi_col),
    ]
    mc_w = Inches(1.55)
    mc_h = Inches(1.05)
    mc_gap = Inches(0.17)
    mc_x = Inches(0.45)
    mc_y = Inches(1.38)

    for i, (val, lbl, col) in enumerate(metric_cards):
        cx = mc_x + i * (mc_w + mc_gap)
        _rect(slide, cx, mc_y, mc_w, mc_h, fill=BLANCO,
              line_color=GRIS_BORDE, line_w=Pt(0.75))
        _text(slide, val, cx, mc_y + Inches(0.12), mc_w, Inches(0.55),
              size=24, bold=True, color=col, align=PP_ALIGN.CENTER, font="Calibri")
        _text(slide, lbl, cx, mc_y + mc_h - Inches(0.28), mc_w, Inches(0.25),
              size=8, bold=True, color=GRIS_OSC, align=PP_ALIGN.CENTER, font="Calibri")

    # Sección DETALLE POR VÍA
    _text(slide, "DETALLE POR VÍA", Inches(0.45), Inches(2.6), Inches(4), Inches(0.3),
          size=10, bold=True, color=TEAL, font="Calibri")

    # Agrupar por vía
    from collections import defaultdict
    vias = defaultdict(list)
    for x in items_emp:
        v = x.get("via","").upper()
        if "AVI" in v or "AER" in v:
            vias["AÉREO"].append(x)
        elif "MAR" in v:
            vias["MARÍTIMO"].append(x)
        elif "CAM" in v:
            vias["CAMIÓN"].append(x)

    row_y = Inches(3.0)
    row_gap = Inches(0.12)
    row_w = Inches(12.0)
    row_x = Inches(0.45)

    via_order = ["AÉREO", "CAMIÓN", "MARÍTIMO"]
    for via_name in via_order:
        items_v = vias.get(via_name, [])
        if not items_v:
            continue
        nv = len(items_v)
        nv_in = sum(1 for x in items_v if x.get("estado") == "IN")
        nv_out = nv - nv_in

        def cnt_canal(canal):
            sub = [x for x in items_v if x.get("canal","").upper() == canal]
            return len([x for x in sub if x.get("estado") == "IN"]), len(sub)

        vi_v, vt_v = cnt_canal("VERDE")
        vi_n, vt_n = cnt_canal("NARANJA")
        vi_r, vt_r = cnt_canal("ROJO")

        _via_row(slide, row_x, row_y, row_w, via_name, nv, nv_in, nv_out,
                 vi_v, vt_v, vi_n, vt_n, vi_r, vt_r)
        row_y += Inches(1.0) + row_gap

    # Target
    # Target note removed - background footer already shows this


def _slide_oficializacion(prs, ofi_items):
    """Slide de oficialización FASA + FSM."""
    fasa = [x for x in ofi_items if "ARGENTINA" in x.get("razon_social","").upper()]
    fsm  = [x for x in ofi_items if "SOLUCIONES" in x.get("razon_social","").upper()]

    def kpi(items):
        n = len(items)
        nin = sum(1 for x in items if x.get("estado") == "IN")
        nout = n - nin
        pct = nin/n*100 if n > 0 else 0
        return pct, nin, nout, n

    slide = prs.slides.add_slide(prs.slide_layouts[6])
    _add_bg(slide, _BG_CONTENIDO_B64)
    _slide_header(slide, "OFICIALIZACIÓN · FASA + FSM")

    panel_total_w = Inches(6.15)
    panel_gap = Inches(0.55)

    pct_f, nin_f, nout_f, tot_f = kpi(fasa)
    _two_panel_kpi(slide, "FASA", "OFICIALIZACIÓN", "24 hs hábiles",
                   tot_f, nin_f, nout_f, pct_f,
                   panel_x=Inches(0.45), panel_w_total=panel_total_w)

    pct_s, nin_s, nout_s, tot_s = kpi(fsm)
    _two_panel_kpi(slide, "FSM", "OFICIALIZACIÓN", "24 hs (48 hs Marítimo)",
                   tot_s, nin_s, nout_s, pct_s,
                   panel_x=Inches(0.45) + panel_total_w + panel_gap,
                   panel_w_total=panel_total_w)



def _slide_canal_verde(prs, lib_items):
    """Slide de canal verde vía aérea."""
    def canal_verde_aereo(items, empresa_kw):
        return [x for x in items
                if empresa_kw in x.get("razon_social","").upper()
                and ("AVI" in x.get("via","").upper() or "AER" in x.get("via","").upper())
                and x.get("canal","").upper() == "VERDE"]

    def all_aereo(items, empresa_kw):
        return [x for x in items
                if empresa_kw in x.get("razon_social","").upper()
                and ("AVI" in x.get("via","").upper() or "AER" in x.get("via","").upper())]

    fasa_aer = all_aereo(lib_items, "ARGENTINA")
    fsm_aer  = all_aereo(lib_items, "SOLUCIONES")

    def kpi_verde(items_all):
        # Canal Verde: % de ops que caen en verde en vía aérea
        n = len(items_all)
        n_verde = sum(1 for x in items_all if x.get("canal","").upper() == "VERDE")
        pct = n_verde / n * 100 if n > 0 else 0
        return pct, n_verde, n - n_verde, n

    slide = prs.slides.add_slide(prs.slide_layouts[6])
    _add_bg(slide, _BG_CONTENIDO_B64)
    _slide_header(slide, "CANAL VERDE · VÍA AÉREA")

    panel_total_w = Inches(6.15)
    panel_gap = Inches(0.55)

    pct_f, nin_f, nout_f, tot_f = kpi_verde(fasa_aer)
    _two_panel_kpi(slide, "FASA", "CANAL VERDE AÉREO", "1 día hábil",
                   tot_f, nin_f, nout_f, pct_f,
                   panel_x=Inches(0.45), panel_w_total=panel_total_w)

    pct_s, nin_s, nout_s, tot_s = kpi_verde(fsm_aer)
    _two_panel_kpi(slide, "FSM", "CANAL VERDE AÉREO", "1 día hábil",
                   tot_s, nin_s, nout_s, pct_s,
                   panel_x=Inches(0.45) + panel_total_w + panel_gap,
                   panel_w_total=panel_total_w)



def _slide_distribucion(prs, lib_items):
    """Slide de distribución de canales."""
    slide = prs.slides.add_slide(prs.slide_layouts[6])
    _add_bg(slide, _BG_CONTENIDO_B64)
    _slide_header(slide, "DISTRIBUCIÓN DE CANALES · LIBERACIONES")

    combos = [
        ("FASA · AÉREO",   "ARGENTINA", lambda v: "AVI" in v or "AER" in v),
        ("FASA · CAMIÓN",  "ARGENTINA", lambda v: "CAM" in v),
        ("FSM · AÉREO",    "SOLUCIONES", lambda v: "AVI" in v or "AER" in v),
        ("FSM · CAMIÓN",   "SOLUCIONES", lambda v: "CAM" in v),
        ("FSM · MARÍTIMO", "SOLUCIONES", lambda v: "MAR" in v),
    ]

    bar_x = Inches(2.2)
    bar_total_w = Inches(9.8)
    bar_h = Inches(0.42)
    row_y = Inches(1.08)
    row_gap = Inches(0.62)

    for label, emp_kw, via_fn in combos:
        subset = [x for x in lib_items
                  if emp_kw in x.get("razon_social","").upper()
                  and via_fn(x.get("via","").upper())]
        n = len(subset)
        if n == 0:
            continue
        n_v = sum(1 for x in subset if x.get("canal","").upper() == "VERDE")
        n_n = sum(1 for x in subset if x.get("canal","").upper() == "NARANJA")
        n_r = sum(1 for x in subset if x.get("canal","").upper() == "ROJO")

        # Label
        _text(slide, label, Inches(0.45), row_y, Inches(1.7), bar_h,
              size=10, bold=True, color=GRIS_OSC, font="Calibri")
        _text(slide, f"{n} ops", Inches(0.45), row_y + bar_h - Inches(0.08),
              Inches(1.7), Inches(0.25), size=8, color=RGBColor(0x88, 0x88, 0x88),
              font="Calibri")

        # Stacked bar
        cx = bar_x
        for count, color in [(n_v, VERDE), (n_n, NARANJA), (n_r, ROJO)]:
            if count <= 0 or n == 0:
                continue
            seg_w = int(bar_total_w * count / n)
            if seg_w < 2:
                seg_w = 2
            _rect(slide, cx, row_y, seg_w, bar_h, fill=color, line_color=None)
            pct = count / n * 100
            if pct > 5:
                _text(slide, f"{count} ({pct:.0f}%)",
                      cx + Inches(0.05), row_y + Inches(0.06), seg_w - Inches(0.08), bar_h - Inches(0.1),
                      size=9, bold=True, color=BLANCO, v_anchor="middle", font="Calibri")
            cx += seg_w

        row_y += bar_h + row_gap

    # Leyenda
    ley_y = Inches(6.8)
    ley_x = Inches(2.2)
    for color, label in [(VERDE, "Canal Verde"), (NARANJA, "Canal Naranja"), (ROJO, "Canal Rojo")]:
        _rect(slide, ley_x, ley_y + Inches(0.04), Inches(0.22), Inches(0.22), fill=color)
        _text(slide, label, ley_x + Inches(0.28), ley_y, Inches(1.5), Inches(0.3),
              size=9, color=GRIS_OSC, font="Calibri")
        ley_x += Inches(2.0)



def _slide_cm(prs, cm_pre_items, cm_apr_items):
    """Slide de certificados mineros."""
    n_pre = len(cm_pre_items)
    nin_pre = sum(1 for x in cm_pre_items if x.get("estado") == "IN")
    nout_pre = n_pre - nin_pre
    kpi_pre = nin_pre / n_pre * 100 if n_pre > 0 else 0

    # Aprobados por rango de días
    def rango(items, d_min, d_max):
        result = []
        for x in items:
            dias = x.get("dias_aprobacion", x.get("dias", 0)) or 0
            try:
                dias = int(dias)
            except (TypeError, ValueError):
                dias = 0
            if d_max is None:
                if dias >= d_min:
                    result.append(x)
            else:
                if d_min <= dias <= d_max:
                    result.append(x)
        return result

    apr_0_7  = rango(cm_apr_items, 0, 7)
    apr_8_15 = rango(cm_apr_items, 8, 15)
    apr_15p  = rango(cm_apr_items, 16, None)
    n_apr_total = len(cm_apr_items)

    slide = prs.slides.add_slide(prs.slide_layouts[6])
    _add_bg(slide, _BG_CONTENIDO_B64)
    _slide_header(slide, "CERTIFICADOS MINEROS")

    # Sección PRESENTADOS
    _text(slide, "PRESENTADOS · KPI DE GESTIÓN",
          Inches(0.45), Inches(1.05), Inches(8), Inches(0.3),
          size=10, bold=True, color=TEAL, font="Calibri")

    kpi_col = _kpi_color(kpi_pre)
    metric_cards = [
        (str(n_pre), "TOTAL", GRIS_OSC),
        (str(nin_pre), "IN", TEAL),
        (str(nout_pre), "OUT", ROJO if nout_pre > 0 else GRIS_OSC),
        (f"{kpi_pre:.0f}%", "KPI", kpi_col),
    ]
    mc_w = Inches(1.55)
    mc_h = Inches(1.0)
    mc_gap = Inches(0.17)
    mc_x = Inches(0.45)
    mc_y = Inches(1.38)

    for i, (val, lbl, col) in enumerate(metric_cards):
        cx = mc_x + i * (mc_w + mc_gap)
        _rect(slide, cx, mc_y, mc_w, mc_h, fill=BLANCO,
              line_color=GRIS_BORDE, line_w=Pt(0.75))
        _text(slide, val, cx, mc_y + Inches(0.1), mc_w, Inches(0.5),
              size=22, bold=True, color=col, align=PP_ALIGN.CENTER, font="Calibri")
        _text(slide, lbl, cx, mc_y + mc_h - Inches(0.28), mc_w, Inches(0.25),
              size=8, bold=True, color=GRIS_OSC, align=PP_ALIGN.CENTER, font="Calibri")

    _text(slide, "Límite: 48 hs hábiles desde TAD Subido",
          Inches(0.45), mc_y + mc_h + Inches(0.08), Inches(8), Inches(0.25),
          size=8, color=RGBColor(0x88, 0x88, 0x88), font="Calibri")

    # Sección APROBADOS
    _text(slide, "APROBADOS · TIEMPO DE APROBACIÓN (informativo)",
          Inches(0.45), Inches(2.87), Inches(10), Inches(0.3),
          size=10, bold=True, color=TEAL, font="Calibri")

    rangos = [
        ("0 a 7 días",  apr_0_7,  TEAL),
        ("8 a 15 días", apr_8_15, NARANJA),
        ("+15 días",    apr_15p,  ROJO),
    ]

    bar_x = Inches(2.4)
    bar_total_w = Inches(9.5)
    bar_h = Inches(0.48)
    row_y = Inches(3.27)
    row_gap = Inches(0.32)

    for lbl, items, color in rangos:
        n = len(items)
        # Label
        _text(slide, lbl, Inches(0.45), row_y + Inches(0.08),
              Inches(1.9), bar_h,
              size=9, color=GRIS_OSC, align=PP_ALIGN.RIGHT, font="Calibri")

        # Fondo barra
        _rect(slide, bar_x, row_y, bar_total_w, bar_h, fill=GRIS_CARD, line_color=None)

        if n > 0 and n_apr_total > 0:
            seg_w = int(bar_total_w * n / n_apr_total)
            if seg_w < 10:
                seg_w = 10
            _rect(slide, bar_x, row_y, seg_w, bar_h, fill=color, line_color=None)
            pct = n / n_apr_total * 100
            label_text = f"{n} exp · {pct:.0f}%"
            _text(slide, label_text, bar_x + Inches(0.1), row_y + Inches(0.06),
                  max(seg_w - int(Inches(0.2)), int(Inches(0.5))), bar_h - Inches(0.1),
                  size=9, bold=True, color=BLANCO, v_anchor="middle", font="Calibri")
        else:
            _text(slide, "Sin expedientes", bar_x + Inches(0.1), row_y + Inches(0.06),
                  Inches(3), bar_h - Inches(0.1), size=9,
                  color=RGBColor(0x88, 0x88, 0x88), v_anchor="middle", font="Calibri")

        row_y += bar_h + row_gap

    _text(slide, f"Total aprobados: {n_apr_total} expedientes",
          Inches(0.45), Inches(6.85), Inches(6), Inches(0.25),
          size=8, color=RGBColor(0x88, 0x88, 0x88), font="Calibri")



# ── Función principal ─────────────────────────────────────────────────────────

def generar_ppt(lib_items, ofi_items, cm_pre_items, cm_apr_items, mes: str) -> bytes:
    """
    Genera el PowerPoint INTERLOG KPI.

    Parámetros
    ----------
    lib_items     : list[dict] — operaciones de liberación procesadas
    ofi_items     : list[dict] — operaciones de oficialización procesadas
    cm_pre_items  : list[dict] — certificados mineros presentados
    cm_apr_items  : list[dict] — certificados mineros aprobados
    mes           : str        — nombre del mes (ej: "Diciembre 2025")

    Retorna
    -------
    bytes del archivo .pptx
    """
    prs = Presentation()
    prs.slide_width  = W
    prs.slide_height = H

    _slide_portada(prs, mes)
    _slide_resumen(prs, lib_items, ofi_items, cm_pre_items)
    # FASA
    fasa_lib = [x for x in lib_items if "ARGENTINA" in x.get("razon_social","").upper()]
    if fasa_lib:
        _slide_liberacion(prs, "ARGENTINA", lib_items)
    # FSM
    fsm_lib = [x for x in lib_items if "SOLUCIONES" in x.get("razon_social","").upper()]
    if fsm_lib:
        _slide_liberacion(prs, "SOLUCIONES", lib_items)
    _slide_oficializacion(prs, ofi_items)
    _slide_canal_verde(prs, lib_items)
    _slide_distribucion(prs, lib_items)
    _slide_cm(prs, cm_pre_items, cm_apr_items)

    buf = io.BytesIO()
    prs.save(buf)
    buf.seek(0)
    return buf.read()
